if (!defined('ABSPATH')) exit;

final class Tager_V47_Discovery {
    const VER='47.0.0';
    public static function init(){
        add_action('init',[__CLASS__,'register'],99);
        add_action('admin_post_tager_v47_save_location',[__CLASS__,'save_location']);
        add_shortcode('tager_v47_vendor_directory',[__CLASS__,'vendor_directory']);
        add_shortcode('tager_v47_market_search',[__CLASS__,'market_search']);
        add_shortcode('tager_v47_vendor_store',[__CLASS__,'vendor_store']);
        add_shortcode('tager_v47_vendor_location_settings',[__CLASS__,'vendor_location_settings']);
        add_action('wp_enqueue_scripts',[__CLASS__,'assets']);
    }
    public static function register(){
        self::ensure_page('vendor-directory','دليل الموردين','[tager_v47_vendor_directory]');
        self::ensure_page('products','المنتجات والسوق','[tager_v47_market_search]');
        self::ensure_page('vendor-store','متجر المورد','[tager_v47_vendor_store]');
        self::ensure_page('vendor-location-settings','مناطق خدمة المورد','[tager_v47_vendor_location_settings]');
    }
    private static function ensure_page($slug,$title,$content){
        $p=get_page_by_path($slug);
        if(!$p){wp_insert_post(['post_type'=>'page','post_status'=>'publish','post_title'=>$title,'post_name'=>$slug,'post_content'=>$content]);return;}
        if(trim((string)$p->post_content)!==$content) wp_update_post(['ID'=>$p->ID,'post_content'=>$content]);
    }
